    20→/** @file*/
    21→
    22→#include "internal_nn_math.h"
    23→#include "riscv_nn_support.h"
    24→
    25→//// Convolution Functions
    26→
    27→int32_t riscv_nn_conv_HWC_s8_s8_s8_sft_bias_fast(const q7_t * in_tensor,
    28→                                const uint16_t in_tensor_dim,
    29→                                const uint16_t in_tensor_ch,
    30→                                const q7_t * ker_weight,
    31→                                const uint16_t out_tensor_ch,
    32→                                const uint16_t ker_dim,
    33→                                const uint16_t pad,
    34→                                const uint16_t stride,
    35→                                const q7_t * bias,
    36→                                const uint16_t bias_lshift,
    37→                                const uint16_t out_rshift,
    38→                                q7_t * out_tensor,
    39→                                const uint16_t out_tensor_dim,
    40→                                q15_t * in_tmp_buf,
    41→                                q7_t * tmp_buf)
    42→{
    43→#ifdef ENA_EMPTY_FUN
    44→    //empty body
    45→#else
    46→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
    47→    {
    48→        /* check if the input dimension meets the constraints */
    49→        return -1;
    50→    }
    51→
    52→#if defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
    53→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
    54→
    55→    /*
    56→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
    57→     *  im2col are done to output in q15_t format from q7_t input
    58→     */
    59→
    60→    q7_t     *pBuffer = (q7_t*)in_tmp_buf;
    61→    q7_t     *pOut = out_tensor;
    62→    int bound_begin = (pad + stride - 1) / stride;
    63→    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;
    64→
    65→    /*
    66→     *  Here we split the entire matrix into three regions depending on the pad situation
    67→     *    Top: i_out_y from 0 to pad - 1
    68→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
    69→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
    70→     */
    71→
    72→    /* top part */
    73→    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
    74→    {
    75→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
    76→        {
    77→            /* This part implements the im2col function */
    78→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
    79→            {
    80→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
    81→                {
    82→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
    83→                    {
    84→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
    85→                    }
    86→                    else
    87→                    {
    88→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
    89→                    }
    90→                    pBuffer += in_tensor_ch;
    91→                }
    92→            }
    93→
    94→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
    95→            {
    96→                pOut = nn_mat_mul_kernel_q7(ker_weight,
    97→                                            (q7_t*)in_tmp_buf,
    98→                                            out_tensor_ch,
    99→                                            in_tensor_ch * ker_dim * ker_dim,
   100→                                            bias_lshift,
   101→                                            out_rshift,
   102→                                            bias,
   103→                                            pOut);
   104→                /* counter reset */
   105→                pBuffer = (q7_t*)in_tmp_buf;
   106→            }
   107→        }
   108→    }
   109→
   110→    /* middle part, here we also divide the x into left, mid and right */
   111→    for (; i_out_y < bound_end; i_out_y++)
   112→    {
   113→        /* left part */
   114→        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
   115→        {
   116→            /* This part implements the im2col function */
   117→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   118→            {
   119→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   120→                {
   121→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
   122→                    {
   123→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
   124→                    }
   125→                    else
   126→                    {
   127→                        nn_dup_s8
   128→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
   129→                    }
   130→                    pBuffer += in_tensor_ch;
   131→                }
   132→            }
   133→
   134→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
   135→            {
   136→                pOut = nn_mat_mul_kernel_q7(ker_weight,
   137→                                            (q7_t*)in_tmp_buf,
   138→                                            out_tensor_ch,
   139→                                            in_tensor_ch * ker_dim * ker_dim,
   140→                                            bias_lshift,
   141→                                            out_rshift,
   142→                                            bias,
   143→                                            pOut);
   144→                /* counter reset */
   145→                pBuffer = (q7_t*)in_tmp_buf;
   146→            }
   147→        }
   148→
   149→        /* mid part */
   150→        for (; i_out_x < bound_end; i_out_x++)
   151→        {
   152→            /* This part implements the im2col function */
   153→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   154→            {
   155→                nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
   156→                pBuffer += in_tensor_ch * ker_dim;
   157→            }
   158→
   159→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
   160→            {
   161→                pOut = nn_mat_mul_kernel_q7(ker_weight,
   162→                                            (q7_t*)in_tmp_buf,
   163→                                            out_tensor_ch,
   164→                                            in_tensor_ch * ker_dim * ker_dim,
   165→                                            bias_lshift,
   166→                                            out_rshift,
   167→                                            bias,
   168→                                            pOut);
   169→                /* counter reset */
   170→                pBuffer = (q7_t*)in_tmp_buf;
   171→            }
   172→        }
   173→
   174→        /* right part */
   175→        for (; i_out_x < out_tensor_dim; i_out_x++)
   176→        {
   177→            /* This part implements the im2col function */
   178→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   179→            {
   180→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   181→                {
   182→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
   183→                    {
   184→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
   185→                    }
   186→                    else
   187→                    {
   188→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
   189→                    }
   190→                    pBuffer += in_tensor_ch;
   191→                }
   192→            }
   193→
   194→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
   195→            {
   196→                pOut = nn_mat_mul_kernel_q7(ker_weight,
   197→                                            (q7_t*)in_tmp_buf,
   198→                                            out_tensor_ch,
   199→                                            in_tensor_ch * ker_dim * ker_dim,
   200→                                            bias_lshift,
   201→                                            out_rshift,
   202→                                            bias,
   203→                                            pOut);
   204→                /* counter reset */
   205→                pBuffer = (q7_t*)in_tmp_buf;
   206→            }
   207→        }
   208→    }
   209→
   210→    for (; i_out_y < out_tensor_dim; i_out_y++)
   211→    {
   212→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
   213→        {
   214→            /* This part implements the im2col function */
   215→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
   216→            {
   217→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
   218→                {
   219→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
   220→                    {
   221→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
   222→                    }
   223→                    else
   224→                    {
   225→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
   226→                    }
   227→                    pBuffer += in_tensor_ch;
   228→                }
   229→            }
   230→
   231→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
   232→            {
   233→                pOut = nn_mat_mul_kernel_q7(ker_weight,
   234→                                            (q7_t*)in_tmp_buf,
   235→                                            out_tensor_ch,
   236→                                            in_tensor_ch * ker_dim * ker_dim,
   237→                                            bias_lshift,
   238→                                            out_rshift,
   239→                                            bias,
   240→                                            pOut);
   241→                /* counter reset */
   242→                pBuffer = (q7_t*)in_tmp_buf;
   243→            }
   244→        }
   245→    }
   246→
   247→    /* check if there is left-over for compute */
   248→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
   249→    if (pBuffer != (q7_t *)in_tmp_buf)
   250→    {
   251→        unsigned vl;
   252→        const q7_t *p_wt = ker_weight;
   253→        int       i;
   254→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
   255→
   256→        vl = __riscv_vsetvl_e32m1(1);
   257→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
   258→
   259→        for (i = 0; i < out_tensor_ch; i++)
   260→        {
   261→            q7_t      *p_in = (q7_t*)in_tmp_buf;
   262→            uint16_t colCnt2 = colCnt;
   263→
   264→            //clear v0~v7
   265→            vl = __riscv_vsetvl_e32m8(colCnt);
   266→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
   267→
   268→            while (colCnt2 > 0)
   269→            {
   270→                vl = __riscv_vsetvl_e8m8(colCnt2);
   271→                //load src1
   272→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
   273→                //load src2
   274→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
   275→                //bump pointers and update loop counter
   276→                colCnt2 -= vl;
   277→                p_wt += vl;
   278→                p_in += vl;
   279→                //set the proper avl/SEW/LMUL values for vd4dot
   280→                vl >>= 2;
   281→                vl = __riscv_vsetvl_e32m8(vl);
   282→                //acc += src1 * src2
   283→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
   284→            }
   285→
   286→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
   287→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
   288→
   289→            //add bias back
   290→            vl = __riscv_vsetvl_e32m1(1);
   291→            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
   292→            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
   293→            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
   294→            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
   295→            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
   296→
   297→            //scale down, clip and store the results
   298→            vl = __riscv_vsetvl_e16mf2(1);
   299→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
   300→            vl = __riscv_vsetvl_e8mf4(1);
   301→            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
   302→            __riscv_vse8(pOut, vSum_i8mf4, vl);
   303→
   304→            bias += vl;
   305→            pOut += vl;
   306→        }
   307→    }
   308→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
   309→    if (pBuffer != (q7_t *)in_tmp_buf)
   310→    {
   311→        unsigned vl;
   312→        const q7_t *p_wt = ker_weight;
   313→        int       i;
   314→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
   315→
   316→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
   317→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
   318→
   319→        for (i = 0; i < out_tensor_ch; i++)
   320→        {
   321→            q7_t      *p_in = (q7_t*)in_tmp_buf;
   322→            uint16_t colCnt2 = colCnt;
   323→
   324→            //clear v0~v7
   325→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   326→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
   327→
   328→            while (colCnt2 > 0)
   329→            {
   330→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
   331→                //load src1
   332→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
   333→                //load src2
   334→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
   335→                //bump pointers and update loop counter
   336→                colCnt2 -= vl;
   337→                p_wt += vl;
   338→                p_in += vl;
   339→                //set the proper avl/SEW/LMUL values for vd4dot
   340→                vl >>= 2;
   341→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   342→                //acc += src1 * src2
   343→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
   344→            }
   345→
   346→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
   347→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
   348→
   349→            //add bias back
   350→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
   351→            NDS_VEC_VLB_V(NDS_VEC_V10, bias);
   352→            NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
   353→            NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
   354→            NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
   355→            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
   356→
   357→            //scale down, clip and store the results
   358→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
   359→            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
   360→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
   361→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
   362→            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
   363→
   364→            bias += vl;
   365→            pOut += vl;
   366→        }
   367→    }
   368→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
   369→    if (pBuffer != (q7_t *)in_tmp_buf)
   370→    {
   371→        unsigned vl;
   372→        const q7_t *pA = ker_weight;
   373→        int       i;
   374→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
   375→
   376→        //set SEW for 1st time VMV_S_X
   377→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
   378→        vl = __riscv_vsetvl_e32m8(colCnt);
   379→
   380→        for (i = 0; i < out_tensor_ch; i++)
   381→        {
   382→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   383→            q7_t      *pB = (q7_t*)in_tmp_buf;
   384→            uint16_t colCnt2 = colCnt;
   385→
   386→            //init
   387→            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
   388→            //clear v8~v15
   389→            vint32m8_t vAcc = __riscv_vundefined_i32m8();
   390→            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);
   391→
   392→            while(colCnt2 > 0)
   393→            {
   394→                vl = __riscv_vsetvl_e8m2(colCnt2);
   395→                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
   396→                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
   397→                //load src1
   398→                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
   399→                //load src2
   400→                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
   401→                //acc += src1 * src2
   402→                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
   403→                //bump pointers and update loop counter
   404→                colCnt2 -= vl;
   405→                pA += vl;
   406→                pB += vl;
   407→            }
   408→
   409→            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
   410→            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
   411→            //move vr results to gpr
   412→            sum = __riscv_vmv_x(vAcc_sum);
   413→
   414→            *pOut++ = NDS_ISA_SATS((sum >> out_rshift), 8);
   415→        }
   416→    }
   417→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
   418→    if (pBuffer != (q7_t *)in_tmp_buf)
   419→    {
   420→        unsigned vl;
   421→        const q7_t *pA = ker_weight;
   422→        int       i;
   423→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
   424→
   425→        //set SEW for 1st time VMV_S_X
   426→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
   427→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
   428→
   429→        for (i = 0; i < out_tensor_ch; i++)
   430→        {
   431→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
   432→            q7_t      *pB = (q7_t*)in_tmp_buf;
   433→            uint16_t colCnt2 = colCnt;
   434→
   435→            //init
